import React from "react";
import Navbar from "../layout/Navbar";
import AdminNavBar from "../layout/AdminNavBar";

export default function Layout({ children }) {
  const role = localStorage.getItem("role");

  const isAdminPanel =
    role === "Admin" || role === "Academic Panel";

  return (
    <div className="min-h-screen w-full m-0 p-0 bg-gray-950 text-white">

      {/* PUBLIC / STUDENT TOP NAV */}
      {!isAdminPanel && <Navbar />}

      {/* ADMIN SIDEBAR */}
      {isAdminPanel && <AdminNavBar />}

      {/* MAIN CONTENT */}
      <div
        className={`
          min-h-screen w-full
          ${isAdminPanel ? "md:ml-64" : ""}
          ${isAdminPanel ? "pt-6" : "pt-20"}
          px-6
        `}
      >
        {children}
      </div>

    </div>
  );
}
